     9→import { INetworkAccount } from '../types/network-account.type';
    10→import { INetworkService, ISweepBaseParams } from '../types/network-service';
    11→import { SupportedNetworks } from '../types/network.type';
    12→
    13→const EVM_TOKEN_ABI = [
    14→  'function balanceOf(address owner) view returns (uint256)',
    15→  'function transfer(address to, uint256 amount) returns (bool)',
    16→];
    17→
    18→export abstract class BaseEvmNetworkService implements INetworkService {
    19→  abstract readonly networkName: SupportedNetworks;
    20→
    21→  constructor(
    22→    protected readonly provider: ethers.JsonRpcProvider,
    23→    protected readonly currencyService: CurrencyService,
    24→    protected readonly goldrushService: GoldrushService,
    25→  ) {}
    26→
    27→  async createAccount(): Promise<INetworkAccount> {
    28→    const wallet = ethers.Wallet.createRandom(this.provider);
    29→    return {
    30→      address: wallet.address,
    31→      privateKey: wallet.privateKey,
    32→      publicKey: wallet.signingKey.publicKey,
    33→      meta: JSON.parse(JSON.stringify(wallet)),
    34→    };
    35→  }
    36→
    37→  async getBalance(address: string): Promise<string> {
    38→    const balance = await this.provider.getBalance(address);
    39→    return ethers.formatEther(balance);
    40→  }
    41→
    42→  async getTokenBalance(
    43→    address: string,
    44→    contractAddress: string,
    45→    decimals: number,
    46→  ): Promise<string> {
    47→    const contract = new ethers.Contract(
    48→      contractAddress,
    49→      EVM_TOKEN_ABI,
    50→      this.provider,
    51→    );
    52→    const balance = await contract.balanceOf(address);
    53→    return ethers.formatUnits(balance, decimals);
    54→  }
    55→
    56→  async sweepToken(
    57→    oneTimeWalletPrivateKey: string,
    58→    currencyCode: string,
    59→    destinationAddress: string,
    60→    amount?: string,
    61→  ): Promise<{ transactionHash: string; amount: string }> {
    62→    try {
    63→      const currency =
    64→        await this.currencyService.getCurrencyByCode(currencyCode);
    65→
    66→      if (!currency || !currency.contractAddress) {
    67→        throw new Error(
    68→          `Currency ${currencyCode} not found or missing contract address`,
    69→        );
    70→      }
    71→
    72→      const wallet = new ethers.Wallet(oneTimeWalletPrivateKey, this.provider);
    73→      const contract = new ethers.Contract(
    74→        currency.contractAddress,
    75→        EVM_TOKEN_ABI,
    76→        wallet,
    77→      );
    78→      const balance = await contract.balanceOf(wallet.address);
    79→
    80→      if (balance === 0n) {
    81→        throw new Error('No tokens to sweep');
    82→      }
    83→
    84→      const sendAmount = amount
    85→        ? ethers.parseUnits(amount, currency.decimalPlaces)
    86→        : balance;
    87→
    88→      if (sendAmount > balance) {
    89→        throw new Error(
    90→          `Insufficient token balance: requested ${sendAmount}, available ${balance}`,
    91→        );
    92→      }
    93→
    94→      const tx = await contract.transfer(destinationAddress, sendAmount);
    95→      const receipt = await tx.wait();
    96→
    97→      const sentAmount = ethers.formatUnits(sendAmount, currency.decimalPlaces);
    98→      return { amount: sentAmount, transactionHash: receipt.hash };
    99→    } catch (error) {
   100→      const errorMessage =
   101→        error instanceof Error ? error.message : String(error);
   102→      throw new Error(`Failed to sweep token: ${errorMessage}`);
   103→    }
   104→  }
   105→
   106→  async sweepBase(
   107→    params: ISweepBaseParams,
   108→  ): Promise<{ transactionHash: string; amount: string }> {
   109→    try {
   110→      const wallet = new ethers.Wallet(params.fromPrivateKey, this.provider);
   111→      const balance = await this.provider.getBalance(wallet.address);
   112→
   113→      if (balance === 0n) {
   114→        throw new Error('No native currency to sweep');
   115→      }
   116→
   117→      const gasPrice = await this.provider.getFeeData();
   118→      const estimatedGas = 21000n;
   119→      const gasCost = (gasPrice.gasPrice || 0n) * estimatedGas;
   120→      const amountToSend = balance > gasCost ? balance - gasCost : 0n;
   121→
   122→      if (amountToSend === 0n) {
   123→        throw new Error('Insufficient balance after gas deduction');
   124→      }
   125→
   126→      const sendAmount = params.amount
   127→        ? new Decimal(params.amount).mul('1000000000000000000')
   128→        : new Decimal(amountToSend.toString());
   129→
   130→      const tx = await wallet.sendTransaction({
   131→        to: params.toAddress,
   132→        value: BigInt(sendAmount.toString()),
   133→        gasLimit: estimatedGas,
   134→      });
   135→
   136→      const receipt = await tx.wait(2);
   137→
   138→      return { transactionHash: receipt.hash, amount: sendAmount.toString() };
   139→    } catch (error) {
   140→      const errorMessage =
   141→        error instanceof Error ? error.message : String(error);
   142→      throw new Error(`Failed to sweep base currency: ${errorMessage}`);
   143→    }
   144→  }
   145→
   146→  async verifyTransaction(transactionHash: string): Promise<boolean> {
   147→    try {
   148→      const receipt =
   149→        await this.provider.getTransactionReceipt(transactionHash);
   150→      return receipt !== null && receipt.status === 1;
   151→    } catch {
   152→      return false;
   153→    }
   154→  }
   155→
   156→  async getTransactionHistory(
   157→    options: IGetTransactionHistoryParams,
   158→  ): Promise<INetworkTransaction[]> {
   159→    if (options.contractAddress) {
   160→      return this.goldrushService.getERC20TransfersToAdressFromDate({
   161→        toAddress: options.address,
   162→        network: this.networkName,
   163→        fromDate: new Date(options.sinceTimestamp),
   164→        contractAddress: options.contractAddress,
   165→      });
   166→    }
   167→    return this.goldrushService.getNativeTransfersToAdressFromDate({
   168→      toAddress: options.address,
   169→      network: this.networkName,
   170→      fromDate: new Date(options.sinceTimestamp),
   171→      contractAddress: options.contractAddress,
   172→    });
   173→  }
   174→}
