     1→import { Inject, Injectable } from '@nestjs/common';
     2→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     3→import { Db } from '@shared/database/types';
     4→import { TronWeb } from 'tronweb';
     5→import { CurrencyService } from '@modules/currency/services/currency.service';
     6→import { Decimal } from 'decimal.js';
     7→import { INetworkAccount } from '../../types/network-account.type';
     8→import { INetworkService, ISweepBaseParams } from '../../types/network-service';
     9→import { SupportedNetworks } from '../../types/network.type';
    10→import { TRC20_ABI } from '../constant';
    11→import { networksConfigs } from '@configs/networks.configs';
    12→import { ConfigType } from '@nestjs/config';
    13→import { TronGridService } from './tron-grid.service';
    14→import {
    15→  IGetTransactionHistoryParams,
    16→  INetworkTransaction,
    17→} from '@modules/networks/types/network.type';
    18→
    19→@Injectable()
    20→export class TronNetworkService implements INetworkService {
    21→  constructor(
    22→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    23→    private readonly currencyService: CurrencyService,
    24→    @Inject(networksConfigs.KEY)
    25→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    26→    private readonly tronGridService: TronGridService,
    27→  ) {
    28→    this.tronWeb = new TronWeb({
    29→      fullHost: this.networksConfig.tron.url,
    30→    });
    31→  }
    32→
    33→  private readonly tronWeb: TronWeb;
    34→
    35→  readonly networkName: SupportedNetworks.TRON = SupportedNetworks.TRON;
    36→
    37→  async createAccount(): Promise<INetworkAccount> {
    38→    const account = await this.tronWeb.createAccount();
    39→
    40→    return {
    41→      address: account.address.base58,
    42→      privateKey: account.privateKey,
    43→      publicKey: account.publicKey,
    44→      meta: JSON.parse(JSON.stringify(account)),
    45→    };
    46→  }
    47→
    48→  async getTokenBalance(
    49→    address: string,
    50→    currencyCode: string,
    51→  ): Promise<string> {
    52→    const currency = await this.currencyService.getCurrencyByCode(currencyCode);
    53→
    54→    if (!currency || !currency.contractAddress) {
    55→      throw new Error(
    56→        `Currency ${currencyCode} not found or missing contract address`,
    57→      );
    58→    }
    59→
    60→    // Use standard TRC-20 ABI instead of fetching from chain
    61→    const contract = this.tronWeb.contract(
    62→      TRC20_ABI.entrys,
    63→      currency.contractAddress,
    64→    );
    65→
    66→    // For balanceOf, we need to specify the 'from' address (any address can call this view function)
    67→    // Using the same address being queried as the caller
    68→    const balance = await contract.methods
    69→      .balanceOf(address)
    70→      .call({ from: address });
    71→
    72→    return new Decimal(balance).div(10 ** currency.decimalPlaces).toString();
    73→  }
    74→
    75→  async getTronBalance(address: string): Promise<number> {
    76→    const balance = await this.tronWeb.trx.getBalance(address);
    77→    return balance;
    78→  }
    79→
    80→  async getTrxBalance(address: string): Promise<string> {
    81→    const balance = new Decimal(await this.tronWeb.trx.getBalance(address));
    82→    return balance
    83→      .div(10 ** 6)
    84→      .toDecimalPlaces(6)
    85→      .toString();
    86→  }
    87→
    88→  async geTtrxBalanceByPrivateKey(privateKey: string): Promise<string> {
    89→    const wallet = this.tronWeb.address.fromPrivateKey(privateKey);
    90→    return this.getTrxBalance(wallet as string);
    91→  }
    92→
    93→  /**
    94→   * Sweeps TRC-20 tokens from a one-time wallet to a destination address
    95→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
    96→   * @param currencyCode Currency code (e.g., 'USDT')
    97→   * @param destinationAddress Address to sweep tokens to
    98→   * @returns Transaction hash
    99→   */
   100→  async sweepToken(
   101→    oneTimeWalletPrivateKey: string,
   102→    currencyCode: string,
   103→    destinationAddress: string,
   104→    amount?: string,
   105→  ): Promise<{ transactionHash: string; amount: string }> {
   106→    try {
   107→      const currency =
   108→        await this.currencyService.getCurrencyByCode(currencyCode);
   109→
   110→      if (!currency || !currency.contractAddress) {
   111→        throw new Error(
   112→          `Currency ${currencyCode} not found or missing contract address`,
   113→        );
   114→      }
   115→
   116→      const contractAddress = currency.contractAddress;
   117→
   118→      // Create wallet from private key
   119→      const wallet = this.tronWeb.address.fromPrivateKey(
   120→        oneTimeWalletPrivateKey,
   121→      );
   122→
   123→      // Create contract instance using standard TRC-20 ABI to get balance
   124→      const contract = this.tronWeb.contract(TRC20_ABI.entrys, contractAddress);
   125→
   126→      // Get balance of the one-time wallet
   127→      const balance = await contract.methods
   128→        .balanceOf(wallet)
   129→        .call({ from: wallet });
   130→
   131→      if (balance.toString() === '0') {
   132→        throw new Error('No tokens to sweep');
   133→      }
   134→
   135→      const rawAmount = amount
   136→        ? new Decimal(amount).mul(10 ** currency.decimalPlaces).toFixed(0)
   137→        : balance.toString();
   138→
   139→      if (new Decimal(rawAmount).gt(balance.toString())) {
   140→        throw new Error(
   141→          `Insufficient token balance: requested ${rawAmount}, available ${balance.toString()}`,
   142→        );
   143→      }
   144→
   145→      // Use triggerSmartContract as per TronWeb documentation
   146→      // https://tronweb.network/docu/docs/Transfer%20Token/
   147→      const functionSelector = 'transfer(address,uint256)';
   148→      const parameter = [
   149→        { type: 'address', value: destinationAddress },
   150→        { type: 'uint256', value: rawAmount },
   151→      ];
   152→
   153→      // Set feeLimit for TRC-20 transfers (consumes energy)
   154→      const feeLimit = 18_000_000; // 18 TRX in SUN
   155→
   156→      // Build the transaction using triggerSmartContract
   157→      const tx = await this.tronWeb.transactionBuilder.triggerSmartContract(
   158→        contractAddress,
   159→        functionSelector,
   160→        { feeLimit }, // Options object with feeLimit
   161→        parameter,
   162→        wallet as string, // issuerAddress - the address that will sign and send the transaction
   163→      );
   164→
   165→      // Sign the transaction with the private key
   166→      const signedTx = await this.tronWeb.trx.sign(
   167→        tx.transaction,
   168→        oneTimeWalletPrivateKey,
   169→      );
   170→
   171→      // Send the signed transaction
   172→      const result = await this.tronWeb.trx.sendRawTransaction(signedTx);
   173→
   174→      // Extract transaction hash from result
   175→      if (result.result) {
   176→        const txHash = result.txid || tx.transaction?.txID || '';
   177→        const sentAmount = new Decimal(rawAmount)
   178→          .div(10 ** currency.decimalPlaces)
   179→          .toString();
   180→        return { transactionHash: txHash, amount: sentAmount };
   181→      } else {
   182→        throw new Error(
   183→          `Transaction failed: ${result.message || 'Unknown error'}`,
   184→        );
   185→      }
   186→    } catch (error) {
   187→      const errorMessage =
   188→        error instanceof Error ? error.message : String(error);
   189→      throw new Error(`Failed to sweep token: ${errorMessage}`);
   190→    }
   191→  }
   192→
   193→  /**
   194→   * Sweeps TRX from a one-time wallet to a destination address
   195→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
   196→   * @param destinationAddress Address to sweep TRX to
   197→   * @returns Transaction hash
   198→   */
   199→  async sweepBase(
   200→    params: ISweepBaseParams,
   201→  ): Promise<{ transactionHash: string; amount: string }> {
   202→    try {
   203→      // Create wallet from private key
   204→      const wallet = this.tronWeb.address.fromPrivateKey(params.fromPrivateKey);
   205→
   206→      // Get balance (in SUN, 1 TRX = 1,000,000 SUN)
   207→      const balance = await this.tronWeb.trx.getBalance(wallet);
   208→
   209→      if (balance === 0) {
   210→        throw new Error('No TRX to sweep');
   211→      }
   212→
   213→      //const sendAmount = new Decimal(params.amount).mul(1_000_000).toNumber();
   214→
   215→      // Calculate amount to send (subtract transaction fee)
   216→      // Current TRX transfer fee is ~1.1 TRX
   217→      // Using 1,200,000 SUN (1.2 TRX) as a safe buffer for fees
   218→      const fee = 1_200_000; // 1.2 TRX in SUN (safe buffer, actual fee ~1.1 TRX)
   219→      const availableBalance = new Decimal(balance)
   220→        .minus(fee)
   221→        .minus(params.amount ?? 0)
   222→        .toNumber();
   223→      //.minus(sendAmount).toNumber());
   224→
   225→      if (availableBalance <= 0) {
   226→        throw new Error('Insufficient balance after fee deduction');
   227→      }
   228→
   229→      let sendAmount = params.amount
   230→        ? new Decimal(params.amount).mul(1_000_000)
   231→        : new Decimal(availableBalance);
   232→
   233→      // Transfer TRX to destination
   234→      // According to TronWeb docs, use sendTrx() for TRX transfers
   235→      // sendTrx() handles transaction creation, signing, and broadcasting automatically
   236→      const tx = await this.tronWeb.trx.sendTrx(
   237→        params.toAddress,
   238→        parseFloat(sendAmount.toString()),
   239→        {
   240→          privateKey: params.fromPrivateKey,
   241→        },
   242→      );
   243→
   244→      return {
   245→        transactionHash: tx.txid,
   246→        amount: sendAmount.div(1_000_000).toString(),
   247→      };
   248→    } catch (error) {
   249→      const errorMessage =
   250→        error instanceof Error ? error.message : String(error);
   251→      throw new Error(`Failed to sweep TRX: ${errorMessage}`);
   252→    }
   253→  }
   254→
   255→  async verifyTransaction(transactionHash: string): Promise<boolean> {
   256→    try {
   257→      const info = await this.tronWeb.trx.getTransactionInfo(transactionHash);
   258→      return info && typeof info.id === 'string' && info.id.length > 0;
   259→    } catch {
   260→      return false;
   261→    }
   262→  }
