     1→import { Injectable, Inject, Logger } from '@nestjs/common';
     2→import { ConfigType } from '@nestjs/config';
     3→import { networksConfigs } from '@configs/networks.configs';
     4→import { TronWeb } from 'tronweb';
     5→import {
     6→  IGetTransactionHistoryParams,
     7→  INetworkTransaction,
     8→} from '@modules/networks/types/network.type';
     9→import Decimal from 'decimal.js';
    10→
    11→@Injectable()
    12→export class TronGridService {
    13→  private readonly logger = new Logger(TronGridService.name);
    14→  private readonly apiKey: string;
    15→  private readonly tronWeb: TronWeb;
    16→
    17→  constructor(
    18→    @Inject(networksConfigs.KEY)
    19→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    20→  ) {
    21→    this.apiKey = this.networksConfig.tron.tronGridApiKey;
    22→    this.tronWeb = new TronWeb({
    23→      fullHost: this.networksConfig.tron.url,
    24→    });
    25→  }
    26→
    27→  /**
    28→   * Gets transaction history for an address using TronGrid API
    29→   * @param params Parameters for fetching transaction history
    30→   * @param params.address The address to get transaction history for
    31→   * @param params.contractAddress Optional contract address for TRC20 token transactions (null for TRX transactions)
    32→   * @param params.sinceTimestamp Optional timestamp to filter transactions after this time (in milliseconds)
    33→   * @returns Array of incoming transactions
    34→   */
    35→  async getTransactionHistory(
    36→    params: IGetTransactionHistoryParams,
    37→  ): Promise<Array<INetworkTransaction>> {
    38→    const { address, contractAddress, decimalPlaces } = params;
    39→    try {
    40→      // TronGrid API endpoint for TRC20 transactions
    41→      // Docs: https://developers.tron.network/reference/get-trc20-transaction-info-by-account-address
    42→      const tronGridUrl = this.networksConfig.tron.url;
    43→      const endpoint = contractAddress
    44→        ? `${tronGridUrl}/v1/accounts/${address}/transactions/trc20`
    45→        : `${tronGridUrl}/v1/accounts/${address}/transactions`;
    46→
    47→      const url = new URL(endpoint);
    48→      if (contractAddress) {
    49→        url.searchParams.set('contract_address', contractAddress);
    50→      }
    51→      if (params.onlyConfirmed) {
    52→        url.searchParams.set('only_confirmed', 'true');
    53→      }
    54→      url.searchParams.set('limit', params?.limit?.toString() ?? '5'); // Get more transactions to ensure we catch the deposit
    55→      if (params.sinceTimestamp) {
    56→        // TronGrid uses milliseconds for min_timestamp,
    57→        console.log('params.sinceTimestamp', params.sinceTimestamp);
    58→        url.searchParams.set(
    59→          'min_timestamp',
    60→          Math.floor(params.sinceTimestamp).toString(),
    61→        );
    62→      }
    63→      // Only get incoming transactions (to address matches our address)
    64→      if (params.onlyTo) {
    65→        url.searchParams.set('only_to', 'true');
    66→      }
    67→
    68→      this.logger.debug({
    69→        message: 'Fetching transaction history from TronGrid',
    70→        url: url.toString(),
    71→        address,
    72→        contractAddress,
    73→      });
    74→
    75→      const response = await fetch(url.toString(), {
    76→        method: 'GET',
    77→        headers: {
    78→          'TRON-PRO-API-KEY': this.apiKey,
    79→        },
    80→      });
    81→
    82→      if (!response.ok) {
    83→        const errorText = await response.text();
    84→        this.logger.error({
    85→          message: 'TronGrid API request failed',
    86→          status: response.status,
    87→          statusText: response.statusText,
    88→          errorText,
    89→        });
    90→        throw new Error(
    91→          `TronGrid API request failed: ${response.status} ${response.statusText} - ${errorText}`,
    92→        );
    93→      }
    94→
    95→      const data = await response.json();
    96→      console.log('data', data);
    97→
    98→      if (!data.success && data.error) {
    99→        this.logger.error({
   100→          message: 'TronGrid API error',
   101→          error: data.error,
   102→        });
   103→        throw new Error(`TronGrid API error: ${data.error}`);
   104→      }
   105→
   106→      const transactions: Array<{
   107→        transactionHash: string;
   108→        amount: string;
   109→        timestamp: number;
   110→        from: string;
   111→        to: string;
   112→      }> = [];
   113→
   114→      // Handle TRC20 transactions response
   115→      if (contractAddress && data.data) {
   116→        for (const tx of data.data) {
   117→          // Only process transactions where our address is the recipient
   118→          if (tx.to?.toLowerCase() !== address.toLowerCase()) {
   119→            continue;
   120→          }
   121→
   122→          // Convert amount from smallest unit (considering token decimals)
   123→          // TronGrid returns amount as a string in smallest units
   124→          const amount =
   125→            new Decimal(tx.value).div(10 ** decimalPlaces).toString() || '0';
   126→          const timestamp = tx.block_timestamp || 0;
   127→
   128→          transactions.push({
   129→            transactionHash: tx.transaction_id || tx.hash || '',
   130→            amount,
   131→            timestamp,
   132→            from: tx.from || '',
   133→            to: tx.to || address,
   134→          });
   135→        }
   136→      } else if (!contractAddress && data.data) {
   137→        // Handle TRX transactions response
   138→        for (const tx of data.data) {
   139→          // Check if this is a TRX transfer (not a contract call)
   140→          if (tx.raw_data?.contract?.[0]?.type !== 'TransferContract') {
   141→            continue;
   142→          }
   143→
   144→          const contract = tx.raw_data.contract[0];
   145→          const parameter = contract.parameter?.value;
   146→
   147→          // Convert hex address to base58 for comparison
   148→          // TronGrid returns addresses in hex format (starting with 41)
   149→          const toAddressBase58 = this.tronWeb.address.fromHex(
   150→            parameter?.to_address,
   151→          );
   152→          const fromAddressBase58 = this.tronWeb.address.fromHex(
   153→            parameter?.owner_address,
   154→          );
   155→
   156→          // Only process transactions where our address is the recipient
   157→          if (toAddressBase58 !== address) {
   158→            continue;
   159→          }
   160→
   161→          const amount =
   162→            new Decimal(parameter?.amount)
   163→              .div(10 ** decimalPlaces)
   164→              .toString() || '0';
   165→          const timestamp = tx.block_timestamp || tx.raw_data?.timestamp || 0;
   166→
   167→          transactions.push({
   168→            transactionHash: tx.txID || '',
   169→            amount,
   170→            timestamp,
   171→            from: fromAddressBase58 || '',
   172→            to: address,
   173→          });
   174→        }
   175→      }
   176→
   177→      return transactions;
   178→    } catch (error) {
   179→      const errorMessage =
   180→        error instanceof Error ? error.message : String(error);
   181→      this.logger.error({
   182→        error,
   183→        message: 'Failed to get transaction history from TronGrid',
   184→        address,
   185→        contractAddress,
   186→      });
   187→      throw new Error(`Failed to get transaction history: ${errorMessage}`);
   188→    }
   189→  }
   190→}
