   170→  /**
   171→   * Sweeps funds from a wallet to a destination address.
   172→   * Multi-layer idempotency: DB (source of truth) → Redis TTL lock → UNIQUE constraint.
   173→   * Safe to retry — returns cached result for completed sweeps, recovers stale pending records.
   174→   */
   175→  async sweepFunds(
   176→    network: SupportedNetworks,
   177→    currencyCode: string,
   178→    options: Required<ISweepBaseParams>,
   179→  ): Promise<{ swept: boolean; transactionHash?: string; amount?: string }> {
   180→    // Layer 1: Check DB first (source of truth)
   181→    const existingRecord = await this.db
   182→      .selectFrom('sweepRecord')
   183→      .selectAll()
   184→      .where('idempotencyKey', '=', options.idempotencyKey)
   185→      .executeTakeFirst();
   186→
   187→    if (existingRecord) {
   188→      return this.handleExistingSweepRecord(existingRecord, network);
   189→    }
   190→
   191→    // Layer 2: Acquire distributed lock with TTL
   192→    const lockKey = `sweep-lock:${options.idempotencyKey}`;
   193→    const locked = await this.redis.set(
   194→      lockKey,
   195→      '1',
   196→      'EX',
   197→      SWEEP_LOCK_TTL_SECONDS,
   198→      'NX',
   199→    );
   200→
   201→    if (!locked) {
   202→      await this.delay(SWEEP_LOCK_RETRY_DELAY_MS);
   203→      const recordAfterWait = await this.db
   204→        .selectFrom('sweepRecord')
   205→        .selectAll()
   206→        .where('idempotencyKey', '=', options.idempotencyKey)
   207→        .executeTakeFirst();
   208→      if (recordAfterWait) {
   209→        return this.handleExistingSweepRecord(recordAfterWait, network);
   210→      }
   211→      throw ExceptionFactory.create({
   212→        exceptionCode: 'network.concurrentSweep',
   213→        statusCode: HttpStatus.BAD_REQUEST,
   214→        message: 'Concurrent sweep in progress for this idempotency key',
   215→      });
   216→    }
   217→
   218→    try {
   219→      // Double-check DB after acquiring the lock (another worker may have completed between Layer 1 and lock)
   220→      const doubleCheck = await this.db
   221→        .selectFrom('sweepRecord')
   222→        .selectAll()
   223→        .where('idempotencyKey', '=', options.idempotencyKey)
   224→        .executeTakeFirst();
   225→
   226→      if (doubleCheck) {
   227→        return this.handleExistingSweepRecord(doubleCheck, network);
   228→      }
   229→
   230→      const currency =
   231→        await this.currencyService.getCurrencyByCode(currencyCode);
   232→      if (!currency) {
   233→        throw ExceptionFactory.create({
   234→          exceptionCode: 'network.currencyNotFoundOnNetwork',
   235→          statusCode: HttpStatus.BAD_REQUEST,
   236→          message: `Currency ${currencyCode} not found on ${network}`,
   237→        });
   238→      }
   239→
   240→      this.logger.debug({
   241→        message: 'Initiating sweep',
   242→        currencyCode,
   243→        network,
   244→        fromAddress: options.fromAddress,
   245→        toAddress: options.toAddress,
   246→        amount: options.amount,
   247→      });
   248→
   249→      // Layer 3: INSERT with UNIQUE constraint as final defense
   250→      let sweepRecordId: UUID;
   251→      try {
   252→        const sweepRecord = await this.db
   253→          .insertInto('sweepRecord')
   254→          .returning(['id'])
   255→          .values({
   256→            currencyCode: currency.code,
   257→            fromAddress: options.fromAddress,
   258→            toAddress: options.toAddress,
   259→            amount: options.amount,
   260→            status: 'pending',
   261→            errorMessage: null,
   262→            idempotencyKey: options.idempotencyKey,
   263→          })
   264→          .executeTakeFirstOrThrow();
   265→        sweepRecordId = sweepRecord.id;
   266→      } catch (insertError: unknown) {
   267→        if (this.isUniqueViolation(insertError)) {
   268→          const raceRecord = await this.db
   269→            .selectFrom('sweepRecord')
   270→            .selectAll()
   271→            .where('idempotencyKey', '=', options.idempotencyKey)
   272→            .executeTakeFirst();
   273→          if (raceRecord) {
   274→            return this.handleExistingSweepRecord(raceRecord, network);
   275→          }
   276→        }
   277→        throw insertError;
   278→      }
   279→
   280→      // Layer 4: Execute blockchain transfer
   281→      try {
   282→        const result = await this.executeTransfer(
   283→          network,
   284→          currencyCode,
   285→          currency,
   286→          options,
   287→        );
   288→
   289→        await this.db
   290→          .updateTable('sweepRecord')
   291→          .set({
   292→            status: 'completed',
   293→            transactionHash: result.transactionHash,
   294→          })
   295→          .where('id', '=', sweepRecordId)
   296→          .execute();
   297→
   298→        return {
   299→          swept: true,
   300→          transactionHash: result.transactionHash,
   301→          amount: result.amount,
   302→        };
   303→      } catch (transferError: unknown) {
   304→        await this.db
   305→          .updateTable('sweepRecord')
   306→          .set({
   307→            status: 'failed',
   308→            errorMessage:
   309→              transferError instanceof Error
   310→                ? transferError.message
   311→                : 'Unknown error',
   312→          })
   313→          .where('id', '=', sweepRecordId)
   314→          .execute();
   315→        throw transferError;
   316→      }
   317→    } finally {
   318→      await this.redis.del(lockKey);
   319→    }
   320→  }
   321→
   322→  private async handleExistingSweepRecord(
   323→    record: Selectable<SweepRecordEntity>,
   324→    network: SupportedNetworks,
   325→  ): Promise<{ swept: boolean; transactionHash?: string; amount?: string }> {
   326→    if (record.status === 'completed') {
   327→      return {
   328→        swept: true,
   329→        transactionHash: record.transactionHash ?? undefined,
   330→        amount: record.amount,
   331→      };
   332→    }
   333→
   334→    if (record.status === 'failed') {
   335→      throw ExceptionFactory.create({
   336→        exceptionCode: 'network.sweepFailed',
   337→        statusCode: HttpStatus.BAD_REQUEST,
   338→        message: `Sweep failed for idempotency key: ${record.idempotencyKey}`,
   339→      });
   340→    }
   341→
   342→    // status === 'pending' — previous attempt may be in-flight or crashed
   343→    const age = Date.now() - new Date(record.createdAt).getTime();
   344→    if (age < STALE_SWEEP_THRESHOLD_MS) {
   345→      throw ExceptionFactory.create({
   346→        exceptionCode: 'network.sweepInProgress',
   347→        statusCode: HttpStatus.BAD_REQUEST,
   348→        message: 'Sweep currently in progress',
   349→      });
   350→    }
   351→
   352→    // Stale pending record — attempt blockchain-level recovery
   353→    this.logger.warn({
   354→      message: 'Stale pending sweep record detected, attempting recovery',
   355→      sweepRecordId: record.id,
   356→      idempotencyKey: record.idempotencyKey,
   357→      ageMs: age,
   358→    });
   359→
   360→    if (record.transactionHash) {
   361→      const confirmed = await this.verifyTransactionOnChain(
   362→        network,
   363→        record.transactionHash,
   364→      );
   365→      if (confirmed) {
   366→        await this.db
   367→          .updateTable('sweepRecord')
   368→          .set({ status: 'completed' })
   369→          .where('id', '=', record.id)
   370→          .where('status', '=', 'pending')
   371→          .execute();
   372→
   373→        this.logger.log({
   374→          message: 'Recovered stale sweep — confirmed on-chain',
   375→          sweepRecordId: record.id,
   376→          transactionHash: record.transactionHash,
   377→        });
   378→
   379→        return {
   380→          swept: true,
   381→          transactionHash: record.transactionHash,
   382→          amount: record.amount,
   383→        };
   384→      }
   385→    }
   386→
   387→    // No tx hash or tx not confirmed — mark as failed so caller can retry
   388→    const casResult = await this.db
   389→      .updateTable('sweepRecord')
   390→      .set({
   391→        status: 'failed',
   392→        errorMessage:
   393→          'Stale pending record — no confirmed on-chain transaction',
   394→      })
   395→      .where('id', '=', record.id)
   396→      .where('status', '=', 'pending')
   397→      .executeTakeFirst();
   398→
   399→    if (BigInt(casResult.numUpdatedRows) === 0n) {
   400→      const refreshed = await this.db
   401→        .selectFrom('sweepRecord')
   402→        .selectAll()
   403→        .where('id', '=', record.id)
   404→        .executeTakeFirst();
   405→      if (refreshed && refreshed.status === 'completed') {
   406→        return {
   407→          swept: true,
   408→          transactionHash: refreshed.transactionHash ?? undefined,
   409→          amount: refreshed.amount,
   410→        };
   411→      }
   412→    }
   413→
   414→    this.notificationsService.sendNotification(
   415→      `Stale sweep record marked as failed: ${record.idempotencyKey}`,
   416→    );
   417→    throw ExceptionFactory.create({
   418→      exceptionCode: 'network.staleSweepRecovered',
   419→      statusCode: HttpStatus.BAD_REQUEST,
   420→      message:
   421→        'Stale sweep record recovered as failed — safe to retry with new attempt',
   422→    });
   423→  }
