   433→    if (currency.contractAddress === null) {
   434→      return service.sweepBase(options);
   435→    }
   436→    return service.sweepToken(
   437→      options.fromPrivateKey,
   438→      currencyCode,
   439→      options.toAddress,
   440→      options.amount,
   441→    );
   442→  }
