    55→
    56→  async process(job: Job<IMonitorDepositJobPayload>): Promise<void> {
    57→    if (job.name === DepositJobsEnum.MONITOR_DEPOSIT) {
    58→      await this.monitorDeposit(job as Job<IMonitorDepositJobPayload>);
    59→      return;
    60→    }
    61→  }
    62→
    63→  /**
    64→   * Monitors a deposit address for incoming transactions
    65→   * Checks the blockchain for transactions matching the deposit criteria
    66→   */
    67→  private async monitorDeposit(
    68→    job: Job<IMonitorDepositJobPayload>,
    69→  ): Promise<void> {
    70→    const { depositId } = job.data;
    71→    const trx = await this.db.startTransaction().execute();
    72→    this.logger.log({ message: 'Monitoring deposit', depositId });
    73→    try {
    74→      const deposit = await this.depositService.getDepositById(depositId, trx, {
    75→        forUpdate: true,
    76→      });
    77→      const currency = await this.currencyService.getCurrencyByCode(
    78→        job.data.currencyCode,
    79→      );
    80→
    81→      if (await this.shouldStopMonitoring(deposit, trx)) {
    82→        await this.depositPoolService.unlockPoolAccount(
    83→          deposit.depositPoolAccountId,
    84→          currency.code,
    85→          trx,
    86→        );
    87→        await trx.commit().execute();
    88→        await this.removeRepeatableMonitorJob(job.repeatJobKey);
    89→        return;
    90→      }
    91→
    92→      const poolAccount = await this.depositPoolService.getAccountById(
    93→        deposit.depositPoolAccountId,
    94→      );
    95→
    96→      // Get currency to determine contract address
    97→
    98→      if (!currency) {
    99→        this.logger.warn({
   100→          message: 'Currency not found',
   101→          currencyCode: job.data.currencyCode,
   102→          network: job.data.network,
   103→        });
   104→        await trx.rollback().execute();
   105→        return;
   106→      }
   107→
   108→      // Check for incoming transactions after deposit creation time
   109→      const depositCreatedAt = deposit.createdAt.getTime();
   110→      const incomingTransactions = await this.checkIncomingTransactions({
   111→        address: poolAccount.address,
   112→        network: job.data.network,
   113→        contractAddress: currency.contractAddress,
   114→        sinceTimestamp: depositCreatedAt,
   115→        decimalPlaces: currency.decimalPlaces,
   116→      });
   117→
   118→      // Find matching transaction for this deposit
   119→      const matchingTransaction = await this.findMatchingTransaction(
   120→        incomingTransactions,
   121→        deposit.amountExpected,
   122→        currency.decimalPlaces,
   123→        currency.minDepositAmount, // minAmount: use expected amount as minimum when not strict
   124→        deposit.createdAt, // dateFrom: use the deposit creation time as the date from
   125→        deposit.strictAmountExpected, // amountStrict: use the deposit's strict flag
   126→      );
   127→
   128→      if (matchingTransaction) {
   129→        await this.completeDeposit(
   130→          {
   131→            depositId: deposit.id,
   132→            network: job.data.network,
   133→            currencyCode: job.data.currencyCode,
   134→            expectedAmount: job.data.expectedAmount,
   135→            poolAccountId: poolAccount.id,
   136→            tenantAccountId: deposit.tenantAccountId,
   137→            failed: false,
   138→            transaction: matchingTransaction.transaction,
   139→            monitorJobKey: job.repeatJobKey,
   140→          },
   141→          trx,
   142→        );
   143→
   144→        await this.depositPoolService.unlockPoolAccount(
   145→          poolAccount.id,
   146→          currency.code,
   147→          trx,
   148→        );
   149→      }
   150→      await trx.commit().execute();
   151→    } catch (error) {
   152→      await trx.rollback().execute();
   153→      this.logger.error({
   154→        error,
   155→        message: 'Failed to monitor deposit',
   156→        depositId,
   157→      });
   158→      // Don't throw - let the job retry
   159→    }
   160→  }
