    26→import { TenantService } from '@modules/tenant/services/tenant.service';
    27→
    28→@Processor(WITHDRAWAL_OUTBOX_EVENTS_QUEUE_NAME)
    29→export class WithdrawalOutboxProcessor extends WorkerHost {
    30→  private readonly logger = new Logger(WithdrawalOutboxProcessor.name);
    31→
    32→  constructor(
    33→    private readonly withdrawalService: WithdrawalService,
    34→    private readonly networksService: NetworksService,
    35→    private readonly currencyService: CurrencyService,
    36→    private readonly outboxEventsService: OutboxEventsService,
    37→    private readonly webhookService: WebhookService,
    38→    private readonly tenantAccountService: TenantAccountService,
    39→    private readonly notificationsService: NotificationsService,
    40→    private readonly tenantService: TenantService,
    41→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    42→  ) {
    43→    super();
    44→  }
    45→
    46→  async process(
    47→    job: Job<
    48→      IOutboxEvent<
    49→        IWithdrawalCreatedEventPayload | IWithdrawalFinishedEventPayload
    50→      >
    51→    >,
    52→  ): Promise<void> {
    53→    if (job.name === WITHDRAWAL_FINISHED_EVENT_NAME) {
    54→      await this.processWithdrawalFinished(
    55→        job.data.payload as IWithdrawalFinishedEventPayload,
    56→      ).catch((error) => {
    57→        this.logger.error({
    58→          error,
    59→          message: 'Failed to process withdrawal-finished outbox event',
    60→          job: job.data,
    61→        });
    62→      });
    63→      return;
    64→    }
    65→
    66→    if (job.name !== WITHDRAWAL_CREATED_EVENT_NAME) return;
    67→
    68→    const { withdrawalId } = job.data.payload as IWithdrawalCreatedEventPayload;
    69→
    70→    this.logger.log({
    71→      message: 'Processing withdrawal',
    72→      withdrawalId,
    73→      jobId: job.id,
    74→    });
    75→
    76→    // Phase 1: Acquire processing lock or resume if already PROCESSING (retry scenario)
    77→    const withdrawal = await this.acquireOrResume(withdrawalId);
    78→    if (!withdrawal) return;
    79→
    80→    // Phase 2: Perform blockchain transfer (outside the transaction to avoid long locks).
    81→    // sweepFunds is idempotent — on retry it returns the cached sweep_record result.
    82→    let finalStatus = WithdrawalStatus.FAILED;
    83→    let transactionHash: string | undefined;
    84→
    85→    try {
    86→      const currency = await this.currencyService.getCurrencyByCode(
    87→        withdrawal.currencyCode,
    88→      );
    89→
    90→      if (!currency) {
    91→        throw new Error(
    92→          `Currency not found for code: ${withdrawal.currencyCode}`,
    93→        );
    94→      }
    95→
    96→      const outstandingAccount =
    97→        await this.networksService.getOutstandingAccountByNetwork(
    98→          currency.network,
    99→        );
   100→
   101→      const sweepResult = await this.networksService.sweepFunds(
   102→        currency.network,
   103→        withdrawal.currencyCode,
   104→        {
   105→          fromPrivateKey: outstandingAccount.privateKey,
   106→          fromAddress: outstandingAccount.address,
   107→          toAddress: withdrawal.address,
   108→          idempotencyKey: `withdrawal-${withdrawalId}`,
   109→          amount: withdrawal.amount,
   110→        },
   111→      );
   112→
   113→      if (!sweepResult.swept) {
   114→        throw new Error(
   115→          `Blockchain transfer failed for withdrawal ${withdrawalId}`,
   116→        );
   117→      }
   118→
   119→      transactionHash = sweepResult.transactionHash;
   120→
   121→      this.logger.log({
   122→        message: 'Blockchain transfer completed',
   123→        withdrawalId,
   124→        transactionHash,
   125→      });
   126→
   127→      finalStatus = WithdrawalStatus.COMPLETED;
   128→    } catch (error) {
   129→      this.logger.error({
   130→        message: 'Withdrawal failed',
   131→        withdrawalId,
   132→        error: error instanceof Error ? error.message : String(error),
   133→      });
   134→
   135→      finalStatus = WithdrawalStatus.FAILED;
   136→    }
   137→
   138→    // Phase 3: Persist final status + publish finished event atomically
   139→    const trx = await this.db
   140→      .startTransaction()
   141→      .setIsolationLevel('read committed')
   142→      .execute();
   143→
   144→    try {
   145→      await this.withdrawalService.updateWithdrawalStatus(
   146→        withdrawalId,
   147→        finalStatus,
   148→        trx,
   149→        { transactionHash },
   150→      );
   151→
   152→      await this.outboxEventsService.publish<IWithdrawalFinishedEventPayload>(
   153→        WITHDRAWAL_FINISHED_EVENT_NAME,
   154→        {
   155→          withdrawalId,
   156→          orderId: withdrawal.orderId,
   157→          tenantId: withdrawal.tenantId,
   158→          tenantAccountId: withdrawal.tenantAccountId,
   159→          status: finalStatus,
   160→          amount: withdrawal.amount,
   161→          amountUsd: withdrawal.amountUsd,
   162→          commissionAmountUsd: withdrawal.commissionAmountUsd,
   163→          currencyCode: withdrawal.currencyCode,
   164→          transactionHash: transactionHash ?? null,
   165→          webhookUrl: withdrawal.webhookUrl ?? null,
   166→        },
   167→        5,
   168→        trx,
   169→      );
   170→
   171→      await trx.commit().execute();
   172→    } catch (error) {
   173→      await trx.rollback().execute();
   174→      this.logger.error({
   175→        message: 'CRITICAL: Failed to persist withdrawal final status',
   176→        withdrawalId,
   177→        targetStatus: finalStatus,
   178→        error: error instanceof Error ? error.message : String(error),
   179→      });
   180→      throw error;
   181→    }
   182→
   183→    if (finalStatus === WithdrawalStatus.FAILED) {
   184→      try {
   185→        await this.withdrawalService.refundWithdrawal(withdrawalId);
   186→      } catch (refundError) {
   187→        this.logger.error({
   188→          message: 'CRITICAL: Failed to refund withdrawal balances',
   189→          withdrawalId,
   190→          error:
   191→            refundError instanceof Error
   192→              ? refundError.message
   193→              : String(refundError),
   194→        });
   195→      }
   196→    }
   197→
   198→    this.logger.log({
   199→      message: `Withdrawal ${finalStatus.toLowerCase()}`,
   200→      withdrawalId,
   201→    });
   202→  }
   203→
   204→  private async processWithdrawalFinished(
   205→    payload: IWithdrawalFinishedEventPayload,
   206→  ): Promise<void> {
   207→    try {
   208→      if (payload.webhookUrl) {
   209→        const tenantAccount = await this.tenantAccountService.getById(
   210→          payload.tenantAccountId,
   211→        );
   212→
   213→        await this.webhookService.addWebhookJob({
   214→          webhookUrl: payload.webhookUrl,
   215→          event: 'withdrawal.statusChanged',
   216→          payload: {
   217→            withdrawalId: payload.withdrawalId,
   218→            orderId: payload.orderId,
   219→            status: payload.status,
   220→            amount: payload.amount,
   221→            currencyCode: payload.currencyCode,
   222→            transactionHash: payload.transactionHash,
   223→          },
   224→          ...(tenantAccount?.signatureKey
   225→            ? { signatureKey: tenantAccount.signatureKey }
   226→            : {}),
   227→        });
   228→      }
   229→    } catch (error) {
   230→      this.logger.error({
   231→        message: 'Failed to enqueue withdrawal webhook',
   232→        withdrawalId: payload.withdrawalId,
   233→        error: error instanceof Error ? error.message : String(error),
   234→      });
   235→    }
   236→    try {
   237→      const tenant = await this.tenantService.getTenant(payload.tenantId);
   238→      if (!tenant) {
   239→        throw new Error(`Tenant not found for id: ${payload.tenantId}`);
   240→      }
   241→      const message =
   242→        `Tenant ${tenant.name} (${payload.tenantId})\n` +
   243→        `Withdrawal ${payload.status}.\n` +
   244→        `AmountUSD: ${payload.amountUsd}\n` +
   245→        `CommissionAmountUSD: ${payload.commissionAmountUsd}\n` +
   246→        `Transaction: ${payload.transactionHash || 'N/A'}`;
   247→
   248→      await this.notificationsService.sendNotification(message);
   249→    } catch (error) {
   250→      this.logger.error({
   251→        message: 'Failed to send withdrawal notification',
   252→        tenantId: payload.tenantId,
   253→        withdrawalId: payload.withdrawalId,
   254→        error: error instanceof Error ? error.message : String(error),
   255→      });
   256→    }
   257→  }
   258→
   259→  /**
   260→   * Acquires the CREATED→PROCESSING lock via serializable CAS,
   261→   * or resumes processing if the withdrawal is already in PROCESSING state (retry after partial failure).
   262→   * Returns null for terminal states (COMPLETED/FAILED) or if the withdrawal doesn't exist.
   263→   */
   264→  private async acquireOrResume(
   265→    withdrawalId: UUID,
   266→  ): Promise<WithdrawalDto | null> {
   267→    const trx = await this.db
   268→      .startTransaction()
   269→      .setIsolationLevel('serializable')
   270→      .execute();
   271→
   272→    try {
   273→      const withdrawal = await this.withdrawalService.getWithdrawalByIdInternal(
   274→        withdrawalId,
   275→        {
   276→          forUpdate: true,
   277→          trx,
   278→        },
   279→      );
   280→
   281→      if (!withdrawal) {
   282→        await trx.rollback().execute();
   283→        this.logger.error({
   284→          message: 'Withdrawal not found, aborting',
   285→          withdrawalId,
   286→        });
   287→        return null;
   288→      }
   289→
   290→      switch (withdrawal.status) {
   291→        case WithdrawalStatus.COMPLETED:
   292→        case WithdrawalStatus.FAILED:
   293→          await trx.rollback().execute();
   294→          this.logger.warn({
   295→            message: 'Withdrawal already in terminal state, skipping',
   296→            withdrawalId,
   297→            currentStatus: withdrawal.status,
   298→          });
   299→          return null;
   300→
   301→        case WithdrawalStatus.PROCESSING:
   302→          await trx.rollback().execute();
   303→          this.logger.warn({
   304→            message:
   305→              'Withdrawal in PROCESSING state, resuming (retry after partial failure)',
   306→            withdrawalId,
   307→          });
   308→          return withdrawal;
   309→
   310→        case WithdrawalStatus.CREATED: {
   311→          const acquired = await this.withdrawalService.compareAndSetStatus(
   312→            withdrawalId,
   313→            WithdrawalStatus.CREATED,
   314→            WithdrawalStatus.PROCESSING,
   315→            { trx },
   316→          );
   317→
   318→          if (!acquired) {
   319→            await trx.rollback().execute();
   320→            this.logger.warn({
   321→              message: 'CAS failed (concurrent processor), skipping',
   322→              withdrawalId,
   323→            });
   324→            return null;
   325→          }
   326→
   327→          await trx.commit().execute();
   328→          return withdrawal;
   329→        }
   330→
   331→        default:
   332→          await trx.rollback().execute();
   333→          this.logger.error({
   334→            message: 'Withdrawal in unexpected state',
   335→            withdrawalId,
   336→            currentStatus: withdrawal.status,
   337→          });
   338→          return null;
   339→      }
   340→    } catch (error) {
   341→      await trx.rollback().execute();
   342→      throw error;
   343→    }
   344→  }
   345→}
