    56→    const startingBlock = await this.getFirstMatchingBlockHeight({
    57→      fromYear: params.fromDate.getUTCFullYear(),
    58→      fromMonth: params.fromDate.getUTCMonth(),
    59→      fromDay: params.fromDate.getUTCDate(),
    60→      fromHour: params.fromDate.getUTCHours(),
    61→      fromMinute: params.fromDate.getUTCMinutes(),
    62→      network: params.network,
    63→    });
    64→    const chain = this.config.networksMap[params.network];
    65→
    66→    const transfers =
    67→      await this.goldrushApiClient.BalanceService.getErc20TransfersForWalletAddressByPage(
    68→        chain,
    69→        params.toAddress,
    70→        {
    71→          contractAddress: params.contractAddress,
    72→          startingBlock: startingBlock,
    73→        },
    74→      );
    75→
    76→    //const updatedBlockHeight = transfers.data
    77→
    78→    //await _trx.updateTable('accountsEthereumTransactionHistoryOffset')
    79→    //const latestBlockHeight = 10115780
    80→    const filteredTransactions: INetworkTransaction[] = [];
    81→    for (const tx of transfers.data.items) {
    82→      if (tx.transfers?.length === 0) {
    83→        continue;
    84→      }
    85→      if (!tx.successful) {
    86→        continue;
    87→      }
    88→      for (const transfer of tx.transfers) {
    89→        if (transfer.block_signed_at < params.fromDate) {
    90→          continue;
    91→        }
    92→
    93→        if (
    94→          transfer.to_address.toLowerCase() === params.toAddress.toLowerCase()
    95→        ) {
    96→          filteredTransactions.push({
    97→            amount: new Decimal(transfer.delta)
    98→              .div(10 ** transfer.contract_decimals)
    99→              .toString(),
   100→            transactionHash: transfer.tx_hash,
   101→            timestamp: tx.block_signed_at.getTime(),
   102→            from: tx.from_address,
   103→            to: params.toAddress,
   104→          });
   105→        }
   106→      }
   107→    }
   108→    console.log({ filteredTransactions });
   109→    return filteredTransactions;
   110→  }
