   112→  async getNativeTransfersToAdressFromDate(
   113→    params: IFetchLatestTransactionHistoryParams,
   114→    _trx?: ControlledTransaction<Database>,
   115→  ): Promise<INetworkTransaction[]> {
   116→    const chain = this.config.networksMap[params.network];
   117→    const now = new Date();
   118→    const bucketSize = 900;
   119→    const dateDiffirence = (now.getTime() - params.fromDate.getTime()) / 1_000;
   120→    const bucketCount = Math.ceil(dateDiffirence / bucketSize);
   121→
   122→    const transactions: INetworkTransaction[] = [];
   123→
   124→    for (let i = 0; i < bucketCount; i++) {
   125→      const bucket =
   126→        Math.floor(now.getTime() / 1000 / bucketSize) - (bucketCount - i - 1);
   127→      const response =
   128→        await this.goldrushApiClient.TransactionService.getTimeBucketTransactionsForAddress(
   129→          chain,
   130→          params.toAddress,
   131→          bucket,
   132→          {
   133→            noLogs: false,
   134→          },
   135→        );
   136→
   137→      const filteredItems = response.data?.items.filter((item) => {
   138→        if (
   139→          !item.successful ||
   140→          item.to_address.toLowerCase() !== params.toAddress.toLowerCase()
   141→        ) {
   142→          return false;
   143→        }
   144→        if (item.block_signed_at < params.fromDate) {
   145→          return false;
   146→        }
   147→        return true;
   148→      });
   149→      transactions.push(
   150→        ...(filteredItems.map((item) => ({
   151→          amount: new Decimal(item.value)
   152→            .div(10 ** item.gas_metadata.contract_decimals)
   153→            .toString(),
   154→          transactionHash: item.tx_hash,
   155→          timestamp: item.block_signed_at.getTime(),
   156→          from: item.from_address,
   157→          to: params.toAddress,
   158→        })) ?? []),
   159→      );
   160→    }
   161→
   162→    return transactions;
   163→  }
   164→
   165→  @Cache({})
   166→  async getFirstMatchingBlockHeight(
   167→    params: IGetFirstMatchingBlockHeightParams,
   168→  ): Promise<number> {
   169→    const dateFrom = new Date(
   170→      params.fromYear,
   171→      params.fromMonth,
   172→      params.fromDay,
   173→      params.fromHour,
   174→      params.fromMinute,
   175→    );
   176→    const dateTo = new Date(dateFrom);
   177→
   178→    dateTo.setSeconds(dateFrom.getSeconds() + 14);
   179→
   180→    const network = params.network || SupportedNetworks.ETHEREUM;
   181→
   182→    const result =
   183→      await this.goldrushApiClient.BaseService.getBlockHeightsByPage(
   184→        GoldrushChainMap[network],
   185→        dateFrom.toISOString(),
   186→        dateTo.toISOString(),
   187→      );
   188→
   189→    const startBlockHeight: number =
   190→      result.data.items[result.data.items.length - 1].height - 1;
   191→    return startBlockHeight;
   192→  }
   193→}
